-- 1. Create the cms_config table
CREATE TABLE IF NOT EXISTS public.cms_config (
  id bigint PRIMARY KEY,
  config jsonb NOT NULL,
  updated_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- 2. Create the resources table
CREATE TABLE IF NOT EXISTS public.resources (
  id bigint PRIMARY KEY,
  title text NOT NULL,
  description text,
  category text,
  size text,
  created_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- 3. Create the simulator_attempts table
CREATE TABLE IF NOT EXISTS public.simulator_attempts (
  id bigint PRIMARY KEY GENERATED ALWAYS AS IDENTITY,
  level integer NOT NULL,
  outcome text NOT NULL,
  dominant_style text,
  created_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- 4. Create the survey_responses table
CREATE TABLE IF NOT EXISTS public.survey_responses (
  id bigint PRIMARY KEY GENERATED ALWAYS AS IDENTITY,
  q1_answer text,
  q2_answer text,
  created_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- Enable Row Level Security (RLS) on all tables
ALTER TABLE public.cms_config ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.resources ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.simulator_attempts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.survey_responses ENABLE ROW LEVEL SECURITY;

-- Drop existing policies if they exist to avoid duplication errors
DROP POLICY IF EXISTS "Allow public read access" ON public.cms_config;
DROP POLICY IF EXISTS "Allow public all access" ON public.cms_config;
DROP POLICY IF EXISTS "Allow public read access" ON public.resources;
DROP POLICY IF EXISTS "Allow public all access" ON public.resources;
DROP POLICY IF EXISTS "Allow public read access" ON public.simulator_attempts;
DROP POLICY IF EXISTS "Allow public all access" ON public.simulator_attempts;
DROP POLICY IF EXISTS "Allow public read access" ON public.survey_responses;
DROP POLICY IF EXISTS "Allow public all access" ON public.survey_responses;

-- Create RLS Policies for cms_config
CREATE POLICY "Allow public read access" ON public.cms_config FOR SELECT USING (true);
CREATE POLICY "Allow public all access" ON public.cms_config FOR ALL USING (true) WITH CHECK (true);

-- Create RLS Policies for resources
CREATE POLICY "Allow public read access" ON public.resources FOR SELECT USING (true);
CREATE POLICY "Allow public all access" ON public.resources FOR ALL USING (true) WITH CHECK (true);

-- Create RLS Policies for simulator_attempts
CREATE POLICY "Allow public read access" ON public.simulator_attempts FOR SELECT USING (true);
CREATE POLICY "Allow public all access" ON public.simulator_attempts FOR ALL USING (true) WITH CHECK (true);

-- Create RLS Policies for survey_responses
CREATE POLICY "Allow public read access" ON public.survey_responses FOR SELECT USING (true);
CREATE POLICY "Allow public all access" ON public.survey_responses FOR ALL USING (true) WITH CHECK (true);

-- 5. Insert initial default configuration row

INSERT INTO public.cms_config (id, config)
VALUES (1, '{"hero":{"title":"The Lighthouse Project","tagline":"Helping people find their way back","mottoPrefix":"Support, ","mottoHighlight":"not solve.","subtitle":"The first support system for a teenager in distress is rarely a therapist or a \"trusted adult\"—it is their friends. We train youth to be the compassionate, non-judgmental guideposts their peers need.","primaryCta":"Try Interactive Story","secondaryCta":"Explore our belief"},"pillars":{"sectionTitle":"The Three Pillars of Peer Support","sectionDesc":"We teach a simple, three-step action framework designed specifically for real-world teenage behaviors and scenarios.","pillar1":{"title":"1. Recognise","desc":"Spot the subtle signals of distress in friends. Understand changes in daily behaviors, withdrawal, altered communication patterns, and online activity before things escalate.","bullets":["Drastic changes in regular routines","Uncharacteristic social media posts","Prolonged withdrawal from friend circles"]},"pillar2":{"title":"2. Approach","desc":"Start low-pressure, supportive conversations. Learn what to say, how to establish a safe space without judging or lecturing, and how to maintain presence when things are awkward.","bullets":["Using non-threatening observations","Creating zero-pressure listening spaces","Expressing care without force-diagnosing"]},"pillar3":{"title":"3. Guide","desc":"Help friends connect to appropriate support without taking on the role of a clinical professional. Know your personal boundaries, and safely guide friends toward experts.","bullets":["Understanding the limit of peer aid","Identifying warm transitions to professionals","Safely handling emergency escalations"]}},"philosophy":{"sectionTitle":"A Different Direction for Youth Mental Health","sectionDesc":"Traditional approaches put the absolute weight of reaching out entirely on the individual already struggling, often categorization-first. The Lighthouse Project focuses on preparing the friends around them.","lighthouse":{"subtitle":"The Lighthouse Model","title":"Empowering the surrounding peer community","body":"Instead of expecting a struggling teenager to seek out institutional support on their own, we equip friends with the confidence, active listening skills, and boundary-awareness to step in and offer immediate emotional first-aid.","list":["Focuses on training the peers who are already around them.","Replaces immediate categorization with patient, active presence.","Prepares teens to connect friends to professional help safely."]},"traditional":{"subtitle":"Traditional Approach","title":"Placing the burden solely on the individual","body":"General mental health approaches focus heavily on expecting the teenager already experiencing deep distress to diagnose their own issues, overcome massive social anxiety, and actively seek out professional services alone.","list":["Assumes a teen in distress will reach out to a trusted adult first.","Categorizes and labels complex emotional issues too early.","Relies on institutional systems teenagers realistically hesitate to use."]}},"wtrh":{"sectionTitle":"What They Really Heard","sectionDesc":"Every response carries an intention. Explore how your words can land differently depending on a friend''s emotional state, and learn to navigate the nuance of support."},"survey":{"sectionTitle":"Share Your Thoughts","sectionDesc":"Your input helps us understand teen mental health dynamics and shape peer-support strategies. Responses are 100% anonymous and no personal details are tracked.","q1Label":"1. What is one thing you wish more people understood about supporting a friend who is struggling emotionally?","q2Label":"2. What would help teenagers feel more comfortable reaching out for support when they need it?"},"contact":{"sectionTitle":"Contact Us","sectionDesc":"Questions, feedback, or interested in learning more? Contact us via email or Instagram.","email":"thelighthouseproject26@gmail.com","instagram":"@thelighthouseproject2026","instagramUrl":"https://instagram.com/thelighthouseproject2026"},"scenarios":{"1":{"friendName":"Aarav","relation":"Classmate & Cricket Friend","avatar":"🏏","background":"Aarav has been exceptionally quiet lately. Today, he missed cricket practice and posted a cryptic story: ''Just tired of pretending it''s fine.'' You decide to DM him.","startStep":"start","steps":{"start":{"speaker":"peer","text":"Hey... thanks for textin. Honestly, just feeling super overwhelmed lately. Cricket was too much today, so I skipped. Just didn''t want to deal with anyone.","options":[{"text":"Have you tried taking a break? Maybe just relax this weekend.","intent":"I wanted to suggest a solution to help him recover and feel better.","heard":"You think I should handle this myself and that resting is an easy fix.","explanation":"When someone is overwhelmed, suggesting a quick fix like ''taking a break'' can make them feel like you are dismissing the depth of their struggle, or putting the burden back on them to solve it rather than just listening.","nextStep":"branch_solution","warning":"Note this response: ''Have you tried taking a break?''. In Level 1, Aarav receives it with mixed feelings, but let''s see how it behaves in subsequent levels.","impact":{"listening":0,"curiosity":-10,"validation":-20,"empathy":-10,"problem_solving":30,"assumptions":10}},{"text":"That sounds super rough. Is it school stuff or just everything building up?","intent":"I wanted to validate his stress and open up space for him to share details.","heard":"They genuinely want to understand what''s going on and are ready to listen.","explanation":"By validating their pain (''That sounds super rough'') and asking an open question (''Is it school stuff or...''), you show that you aren''t rushing to fix the issue. This creates a safe space for them to open up further.","nextStep":"branch_empathetic","impact":{"listening":30,"curiosity":30,"validation":20,"empathy":20,"problem_solving":0,"assumptions":-10}},{"text":"You''ll be okay, everyone feels like that sometimes! Don''t let it get to you.","intent":"I wanted to encourage him and normalize his feelings so he feels less alone.","heard":"My feelings aren''t that serious or unusual. I should stop complaining.","explanation":"Well-meaning attempts to normalize feelings or encourage someone to ''stay positive'' often feel like minimization. Normalizing a struggle shouldn''t come at the cost of acknowledging the person''s unique distress.","nextStep":"branch_minimize","impact":{"listening":-10,"curiosity":-20,"validation":-30,"empathy":-10,"problem_solving":0,"assumptions":20}}]},"branch_solution":{"speaker":"peer","text":"Idk, everyone keeps telling me to take a break, but my parents are breathing down my neck about exams. I can''t just stop.","options":[{"text":"I get it, but your health comes first. They''ll understand if you explain it.","intent":"I wanted to reassure him that his parents would prioritize his well-being.","heard":"You don''t understand how strict my parents actually are.","explanation":"Telling a friend what their parents will or won''t understand is an assumption. By asserting this, you inadvertently minimize the real fear and pressure they feel, making them feel misunderstood.","nextStep":"failure_end","impact":{"listening":0,"curiosity":-10,"validation":-10,"empathy":10,"problem_solving":20,"assumptions":10}},{"text":"That pressure must feel incredibly heavy. No wonder you skipped practice.","intent":"I wanted to acknowledge and validate the weight of his parental pressure.","heard":"They see how hard this is for me and don''t expect me to just fix it.","explanation":"This response validates the friend''s emotional state directly and connects it to their actions (''No wonder you skipped practice''). It shows you understand their reality rather than arguing with it.","nextStep":"success_end","impact":{"listening":30,"curiosity":10,"validation":30,"empathy":30,"problem_solving":-10,"assumptions":-15}}]},"branch_empathetic":{"speaker":"peer","text":"Everything tbh. My parents expect straight A''s, and I feel like I''m letting everyone down. Literally feel like I can''t breathe sometimes.","options":[{"text":"That sounds incredibly heavy, Aarav. Carrying all that expectation alone is a lot.","intent":"I wanted to express deep empathy and validate how hard his situation is.","heard":"I don''t have to pretend to be strong around them. They get it.","explanation":"Acknowledge the weight of the emotion and the feeling of isolation (''Carrying all that expectation alone''). It signals that you are willing to sit with them in their pain without trying to force a resolution.","nextStep":"success_end","impact":{"listening":30,"curiosity":10,"validation":30,"empathy":30,"problem_solving":0,"assumptions":-10}},{"text":"Why don''t we make a study schedule together? That might make it feel less scary.","intent":"I wanted to help him structure his workload to resolve the issue.","heard":"Instead of listening, they want to give me chores to do.","explanation":"Offering a practical tool like a ''study schedule'' when someone is sharing how overwhelmed they are feels like homework. In distress, people need connection and understanding first, not action items.","nextStep":"failure_end","impact":{"listening":0,"curiosity":-10,"validation":-20,"empathy":0,"problem_solving":30,"assumptions":15}}]},"branch_minimize":{"speaker":"peer","text":"Yeah, true. Probably just being dramatic. Nvm. I''m gonna go sleep.","options":[{"text":"Wait, sorry, I didn''t mean to make it sound like you''re dramatic. I''m listening.","intent":"I wanted to apologize, adjust my tone, and validate his feelings.","heard":"They realize they misstepped and are willing to correct themselves to listen.","explanation":"Taking immediate accountability for a conversational misstep builds trust. By apologizing and shifting back to active listening, you show that their comfort is more important than your ego.","nextStep":"branch_empathetic","impact":{"listening":20,"curiosity":10,"validation":25,"empathy":20,"problem_solving":0,"assumptions":-20}},{"text":"Alright, sleep well! Talk tomorrow.","intent":"I wanted to give him space and avoid bothering him further.","heard":"They are relieved the conversation is over and don''t really want to deal with it.","explanation":"Allowing a friend to shut down and withdraw after they felt dismissed confirms their suspicion that they were a burden. It closes the door on the support they actually needed.","nextStep":"failure_end","impact":{"listening":-20,"curiosity":-20,"validation":-10,"empathy":-10,"problem_solving":0,"assumptions":10}}]},"success_end":{"speaker":"peer","text":"Thanks for listening, seriously. It actually makes it feel a bit lighter just saying it. We should play some games tomorrow.","reactions":["❤️"],"options":[],"isOutcome":true,"outcomeType":"success","outcomeTitle":"Successful Connection","outcomeText":"Successful Connection: You prioritized listening and validation. Aarav felt safe enough to share his feelings, reinforcing that he is valued for who he is rather than his performance."},"failure_end":{"speaker":"peer","text":"Yeah, whatever. Look, I don''t really want a lecture right now. I''m just gonna head out. Talk later.","reactions":["😢"],"options":[],"isOutcome":true,"outcomeType":"failure","outcomeTitle":"Disconnection","outcomeText":"Disconnection: Aarav withdrew. Rushing to solve his problems or minimizing his pain made him feel misunderstood. Remember: Support, don''t solve."}}},"2":{"friendName":"Riya","relation":"Close Group Friend","avatar":"🍿","background":"Riya has flaked on hanging out three times this month. Today, she cancels again last-minute with a text message. You decide to reply.","startStep":"start","steps":{"start":{"speaker":"peer","text":"hey sorry but i can''t make it to cinema tonight. something came up... super sorry to flake again 😭","options":[{"text":"All good! Let us know when you''re free next.","intent":"I wanted to be chill and avoid making her feel guilty.","heard":"They don''t really care if I''m there or not. I''m easily forgotten.","explanation":"While trying to sound ''chill'' prevents guilt, it can also sound indifferent. For someone struggling with isolation or anxiety, this response can be interpreted as a lack of care about their presence.","nextStep":"branch_chill","impact":{"listening":10,"curiosity":-10,"validation":0,"empathy":0,"problem_solving":0,"assumptions":10}},{"text":"Have you tried taking a break? Maybe you just need to rest.","intent":"I wanted to offer a helpful tip to solve her flaking issue by suggesting rest.","heard":"They are writing me off. It feels like they are saying ''fine, just stay home.''","explanation":"Since she has canceled multiple times, recommending a ''break'' functions differently than in Level 1. It acts as an easy dismissal—telling her to remain isolated, confirming her fears of being written off.","nextStep":"branch_rest_dismissive","warning":"⚠️ Context Check: In Level 1, ''taking a break'' felt like standard advice. But in this scenario, where she has canceled repeatedly, offering this advice makes her feel excluded and pushed away, showing how context shifts impact.","impact":{"listening":-10,"curiosity":-20,"validation":-20,"empathy":-10,"problem_solving":30,"assumptions":20}},{"text":"Is everything okay? You''ve cancel''d a few times recently, I''m getting a bit worried.","intent":"I wanted to notice her behavior pattern gently and show concern for her well-being.","heard":"They are paying attention to me. They notice I''m not okay and care.","explanation":"Gently naming a pattern of behavior (''You''ve canceled a few times recently'') and expressing concern shows that you notice their absence and care about their well-being, paving the way for honest conversation.","nextStep":"branch_worried","impact":{"listening":30,"curiosity":30,"validation":25,"empathy":30,"problem_solving":0,"assumptions":-10}}]},"branch_chill":{"speaker":"peer","text":"Yeah, totally. Have fun guys. I''ll just see you at school.","options":[{"text":"Are you sure everything is alright? You don''t seem like yourself.","intent":"I wanted to double check and express care despite my initially casual response.","heard":"They care enough to check twice even when I gave a dismissive reply.","explanation":"Checking in twice shows persistence and genuine care. It lets the friend know that their initial deflective answer didn''t fool you, and that you are truly there to listen.","nextStep":"branch_worried","impact":{"listening":20,"curiosity":30,"validation":20,"empathy":20,"problem_solving":0,"assumptions":-10}},{"text":"Alright, cool. See you Monday!","intent":"I wanted to respect her boundaries and keep things low-key.","heard":"We are drifting apart and they are completely fine with it.","explanation":"Closing the loop with a simple ''See you Monday'' confirms their feeling of disconnection. Responding too casually to repeated withdrawal can accelerate a friend''s isolation.","nextStep":"failure_end","impact":{"listening":-20,"curiosity":-20,"validation":-10,"empathy":-15,"problem_solving":0,"assumptions":10}}]},"branch_rest_dismissive":{"speaker":"peer","text":"Yeah, I guess so. I''ll just stay in. You guys have fun.","options":[{"text":"Wait, I didn''t mean to sound dismissive! I really want to see you. Is something going on?","intent":"I wanted to correct my mistake, showing I want her included.","heard":"They care about my presence and want to check on my well-being.","explanation":"Recognizing that your advice felt dismissive and correcting course immediately shifts the dynamic. It shows you want them there and care about the underlying reason for their cancellation.","nextStep":"branch_worried","impact":{"listening":30,"curiosity":25,"validation":20,"empathy":25,"problem_solving":-15,"assumptions":-20}},{"text":"Yeah, get some rest! Talk later.","intent":"I wanted to encourage her to follow through on resting.","heard":"They are happy to leave me behind. The distance is growing.","explanation":"Doubling down on ''get some rest'' when the friend expressed that they felt written off solidifies their isolation, showing that you aren''t paying attention to the relational distance.","nextStep":"failure_end","impact":{"listening":-20,"curiosity":-20,"validation":-10,"empathy":-10,"problem_solving":20,"assumptions":10}}]},"branch_worried":{"speaker":"peer","text":"Honestly... everything has been a mess. I''ve been feeling super anxious and depressed, and leaving the house literally gives me panic attacks. I''ve just been hiding.","voiceNote":true,"duration":"0:34","options":[{"text":"That sounds incredibly terrifying, Riya. I had no idea you were dealing with that.","intent":"I wanted to validate her panic and acknowledge her painful experience.","heard":"My anxiety is real and they aren''t judging me for hiding.","explanation":"Validating a severe emotion (''That sounds incredibly terrifying'') rather than downplaying it or rushing to fix it provides immense relief. It signals that you are a safe person to be vulnerable around.","nextStep":"success_end","impact":{"listening":30,"curiosity":15,"validation":30,"empathy":30,"problem_solving":0,"assumptions":-10}},{"text":"You should really talk to a doctor. I can send you a link to an online therapist.","intent":"I wanted to immediately solve her panic attacks with professional help.","heard":"I am a problem that needs to be handed off to someone else. They can''t handle me.","explanation":"Jumping straight to a professional handoff without first validating their disclosure feels like rejection. Even if professional help is needed eventually, a friend''s first job is to show emotional presence.","nextStep":"failure_end","impact":{"listening":0,"curiosity":-10,"validation":-20,"empathy":10,"problem_solving":30,"assumptions":10}}]},"success_end":{"speaker":"peer","text":"Thanks for not being mad. It means so much that you checked on me. Let''s Facetime tomorrow?","reactions":["❤️"],"options":[],"isOutcome":true,"outcomeType":"success","outcomeTitle":"Successful Connection","outcomeText":"Successful Connection: You noticed the pattern, avoided simple solutions, and validated Riya''s anxiety. She felt safe to explain her withdrawal, preserving the friendship."},"failure_end":{"speaker":"peer","text":"Yeah, okay. Thanks. I''m gonna go now.","reactions":["😢"],"options":[],"isOutcome":true,"outcomeType":"failure","outcomeTitle":"Disconnection","outcomeText":"Disconnection: Riya withdrew further. Suggesting ''taking a break'' when she was already isolated, or jumping straight to professional handoff without listening, validated her fears of being a burden."}}},"3":{"friendName":"Kavya","relation":"Study Partner","avatar":"📚","background":"Kavya spent three weeks preparing for the debate team tryouts but didn''t make the cut. She is posting memes and making self-deprecating jokes in the chat.","startStep":"start","steps":{"start":{"speaker":"peer","text":"lmao shocker, I didn''t make the team. naturally, because my brain has the capacity of a potato 🥔😂 guess who''s destined for failure!","options":[{"text":"Lmao stop, you''re not a potato! You''ll get it next year.","intent":"I wanted to match her joke and offer light reassurance.","heard":"They don''t want to deal with my actual sadness, so I have to keep joking.","explanation":"Playing along with self-deprecating humor and offering empty reassurance (''You''ll get it next year'') sends a message that you are uncomfortable with their actual disappointment, forcing them to keep laughing off their pain.","nextStep":"branch_laugh","impact":{"listening":10,"curiosity":-15,"validation":-10,"empathy":10,"problem_solving":0,"assumptions":10}},{"text":"Have you tried taking a break? You worked really hard, maybe you need space from debate.","intent":"I wanted to suggest a solution (taking a break) to solve her disappointment.","heard":"They think I failed because I didn''t manage myself well, or they want me to give up.","explanation":"Telling someone who just failed to ''take a break'' can be interpreted as telling them to quit or suggesting they couldn''t handle the pressure. It focus-shifts to their competence rather than validating their hurt.","nextStep":"branch_break_potato","warning":"⚠️ Context Check: Offering ''taking a break'' here feels like telling her to quit or that she is weak, which lands as dismissive rather than supportive.","impact":{"listening":-10,"curiosity":-20,"validation":-20,"empathy":-10,"problem_solving":35,"assumptions":15}},{"text":"That really sucks, Kavya. I know how much you wanted this and how hard you studied.","intent":"I wanted to validate her disappointment directly, ignoring the joke to acknowledge her hard work.","heard":"I don''t have to pretend to laugh. It''s okay that I''m upset about this.","explanation":"Bypassing the defense mechanism of humor to address the disappointment directly (''That really sucks'') shows you see through the mask. It permits them to drop the jokes and express genuine feelings.","nextStep":"branch_validate","impact":{"listening":30,"curiosity":20,"validation":30,"empathy":30,"problem_solving":0,"assumptions":-10}}]},"branch_laugh":{"speaker":"peer","text":"Haha yeah, next year... assuming I haven''t failed out of school by then. I literally flunked the practice quiz today too. Just dumb I guess.","options":[{"text":"You''re not dumb at all! You''re literally one of the smartest people I know.","intent":"I wanted to boost her self-esteem and contradict her self-doubt.","heard":"They are trying to argue with my feelings rather than hearing how stressed I am.","explanation":"Arguing against a friend''s negative self-talk, even with compliments, can feel invalidating. They don''t need you to dispute their logic; they need you to understand how deeply they are hurting right now.","nextStep":"failure_end","impact":{"listening":10,"curiosity":-10,"validation":-20,"empathy":10,"problem_solving":0,"assumptions":10}},{"text":"It sounds like you''re putting a lot of pressure on yourself. Failing the quiz must have felt awful after the debate news.","intent":"I wanted to validate the emotional combination of failures she is experiencing.","heard":"They see my stress. I don''t have to defend my intelligence; they understand the weight.","explanation":"This response connects the dots between multiple stressors (''debate news'' and ''quiz'') and validates the emotional toll. It shows active listening and deep perspective-taking.","nextStep":"branch_validate","impact":{"listening":30,"curiosity":15,"validation":30,"empathy":30,"problem_solving":0,"assumptions":-5}}]},"branch_break_potato":{"speaker":"peer","text":"Yeah, whatever. Maybe debate isn''t my thing anyway. I''ll just study alone.","options":[{"text":"Wait, I didn''t mean to say you should quit. You''re great at debate! I know you''re hurting.","intent":"I wanted to correct my mistake and validate her pain.","heard":"They realize they made me feel bad and are trying to listen now.","explanation":"Catching a misunderstanding and clarifying that you recognize their hurt over their competence shifts the interaction back to a supportive, empathetic connection.","nextStep":"branch_validate","impact":{"listening":25,"curiosity":20,"validation":20,"empathy":25,"problem_solving":-15,"assumptions":-15}},{"text":"Yeah, maybe a break will help you find other interests.","intent":"I wanted to encourage a positive spin on her taking a break.","heard":"They agree that I''m not cut out for this. I should just fade out.","explanation":"Agreeing that they should look for ''other interests'' after a failure reinforces their insecurity that they aren''t good enough, making them feel like you agree with their self-doubt.","nextStep":"failure_end","impact":{"listening":-20,"curiosity":-20,"validation":-25,"empathy":-15,"problem_solving":20,"assumptions":10}}]},"branch_validate":{"speaker":"peer","text":"It just feels so embarrassing. I told everyone I was trying out, and now I feel like a total failure. I''m just so tired of trying so hard and getting nothing.","options":[{"text":"I completely get it. It''s exhausting to put your heart into something and have it not work out.","intent":"I wanted to offer validation and match her feeling of exhaustion.","heard":"They understand the fatigue. I''m allowed to feel defeated for a bit.","explanation":"Matching the feeling of exhaustion (''It''s exhausting to put your heart into...'') normalizes the natural fatigue of tryouts and disappointment, showing solidarity and comforting them in defeat.","nextStep":"success_end","impact":{"listening":30,"curiosity":10,"validation":30,"empathy":30,"problem_solving":0,"assumptions":-10}},{"text":"Don''t say that! You''ll get the next thing. What is the next club you want to try?","intent":"I wanted to motivate her and solve her defeat by redirecting to a new goal.","heard":"My embarrassment is uncomfortable for them. They want me to just move on.","explanation":"Quickly pushing someone to move on to the ''next club'' makes them feel like their current sadness and embarrassment are too inconvenient to sit with. It prioritizes action over emotional processing.","nextStep":"failure_end","impact":{"listening":0,"curiosity":-20,"validation":-25,"empathy":-10,"problem_solving":30,"assumptions":15}}]},"success_end":{"speaker":"peer","text":"Yeah... it really is. Thanks for saying that. I think I''m just gonna mope for tonight, but let''s study together on Sunday?","reactions":["❤️"],"options":[],"isOutcome":true,"outcomeType":"success","outcomeTitle":"Successful Connection","outcomeText":"Successful Connection: You ignored the humorous mask and validated Kavya''s embarrassment. By letting her express disappointment, she felt supported and ready to reconnect."},"failure_end":{"speaker":"peer","text":"Yeah. Anyway, I have to study. See ya.","reactions":["😢"],"options":[],"isOutcome":true,"outcomeType":"failure","outcomeTitle":"Disconnection","outcomeText":"Disconnection: Kavya shut down. Offering quick study solutions, lecturing her not to be sad, or trying to redirect her goals minimized her embarrassment, making her retreat."}}},"4":{"friendName":"Group Chat","relation":"Dev & Rohan","avatar":"📱","background":"You, Dev, and Rohan are in a group chat. You and Dev went to the arcade yesterday but Rohan wasn''t invited. Dev posts a picture from the arcade, and Rohan responds passive-aggressively.","startStep":"start","steps":{"start":{"speaker":"peer","text":"Rohan: looks great. glad you guys had fun.","options":[{"text":"Sorry Rohan! We thought you were busy studying for the physics exam anyway.","intent":"I wanted to explain why he wasn''t invited to resolve the awkwardness and avoid guilt.","heard":"They decided for me that I shouldn''t be invited, rather than asking me. I was excluded by choice.","explanation":"Using an excuse like ''we thought you were busy'' shifts the blame to the friend''s schedule. It takes away their agency to choose whether they wanted to join or take a break, heightening their sense of exclusion.","nextStep":"branch_excuse","impact":{"listening":10,"curiosity":-20,"validation":-20,"empathy":-10,"problem_solving":10,"assumptions":35}},{"text":"We missed you Rohan! We only went for like an hour because we were nearby.","intent":"I wanted to minimize the trip to make him feel less left out.","heard":"They think my feelings of being excluded aren''t a big deal because the trip was short.","explanation":"Minimizing the event (''only went for an hour'') attempts to make the exclusion seem minor, but it actually trivializes their feelings. The hurt comes from being forgotten, regardless of how long the outing was.","nextStep":"branch_minimize_outing","impact":{"listening":15,"curiosity":-10,"validation":-15,"empathy":0,"problem_solving":0,"assumptions":15}},{"text":"Hey Rohan, sorry we didn''t invite you. It was a last minute trip, but it was wrong of us to not drop a text. We really missed having you.","intent":"I wanted to take direct accountability, apologize, and validate his exclusion.","heard":"They admit they made a mistake and care about my feelings and presence.","explanation":"A clean, excuse-free apology that takes responsibility and validates the exclusion is highly effective. It addresses the emotional impact directly and restores mutual respect.","nextStep":"branch_apology","impact":{"listening":30,"curiosity":15,"validation":30,"empathy":30,"problem_solving":-10,"assumptions":-20}}]},"branch_excuse":{"speaker":"peer","text":"Rohan: right, because I''m not allowed to take a break from studying? whatever.","options":[{"text":"I''m sorry Rohan, you''re right. We shouldn''t have assumed. We messed up.","intent":"I wanted to drop the excuses and apologize sincerely.","heard":"They see my point and are owning up to it.","explanation":"Dropping defensive excuses when called out (''We shouldn''t have assumed'') builds safety. It validates the friend''s critique and shows a willingness to prioritize the relationship over saving face.","nextStep":"branch_apology","impact":{"listening":30,"curiosity":15,"validation":35,"empathy":30,"problem_solving":-15,"assumptions":-30}},{"text":"We were just trying to help you study! No need to get so defensive.","intent":"I wanted to defend our original intention of helping him study.","heard":"They are blaming me for being upset about being left out. They don''t care.","explanation":"Accusing an excluded friend of being ''defensive'' shifts the blame onto their reaction. It gaslights their natural hurt and makes them feel like the problem is their sensitivity rather than the exclusion.","nextStep":"failure_end","impact":{"listening":-20,"curiosity":-25,"validation":-30,"empathy":-20,"problem_solving":0,"assumptions":20}}]},"branch_minimize_outing":{"speaker":"peer","text":"Rohan: if it wasn''t a big deal then why post pictures? just say you didn''t want me there.","options":[{"text":"That''s not true at all! We always want you there. It was just a mistake, and I''m sorry.","intent":"I wanted to reassure him of his place in the group and apologize.","heard":"They are trying to fix it, but it feels like damage control.","explanation":"Reassuring a friend of their value while apologizing helps calm insecurity, though because it follows a minimisation attempt, it can still feel a bit like damage control unless followed by genuine connection.","nextStep":"branch_apology","impact":{"listening":20,"curiosity":10,"validation":20,"empathy":20,"problem_solving":0,"assumptions":-10}},{"text":"Dude, it''s just an arcade. Why are you making such a huge deal out of this?","intent":"I wanted to challenge what felt like an overreaction to a small hangout.","heard":"They think I''m dramatic and don''t value my friendship.","explanation":"Trivializing their reaction (''Why are you making such a huge deal'') invalidates their underlying fear of being replaced in the group. It replaces empathy with irritation, leading to disconnection.","nextStep":"failure_end","impact":{"listening":-30,"curiosity":-30,"validation":-35,"empathy":-30,"problem_solving":0,"assumptions":30}}]},"branch_apology":{"speaker":"peer","text":"Rohan: yeah it just sucks seeing you guys hang out without even asking. feels like I''m being replaced.","options":[{"text":"You could never be replaced Rohan. You''re our best friend. Let''s all go to the arcade together this Saturday, our treat.","intent":"I wanted to validate his insecurity and plan an inclusive outing to repair the dynamic.","heard":"I am still a central part of this friendship and they want to make things right.","explanation":"This response provides reassurance against their specific fear (''never be replaced'') and translates that reassurance into concrete action (''arcade together this Saturday''), actively repairing the rift.","nextStep":"success_end","impact":{"listening":30,"curiosity":20,"validation":30,"empathy":30,"problem_solving":20,"assumptions":-15}},{"text":"Well we are talking to you now, aren''t we? You don''t need to feel like that.","intent":"I wanted to prove that we still care by highlighting our current text conversation.","heard":"They want me to stop sharing my insecurities because it makes them uncomfortable.","explanation":"Saying ''we are talking to you now'' is a superficial defense. It treats communication as a checklist rather than addressing the actual emotional distance the friend is feeling.","nextStep":"failure_end","impact":{"listening":0,"curiosity":-20,"validation":-25,"empathy":-10,"problem_solving":0,"assumptions":10}}]},"success_end":{"speaker":"peer","text":"Rohan: okay. thanks guys. sorry for being passive aggressive, just got in my feelings. Saturday sounds good.","reactions":["❤️","👍"],"options":[],"isOutcome":true,"outcomeType":"success","outcomeTitle":"Successful Connection","outcomeText":"Successful Connection: You navigated complex group dynamics by dropping excuses, acknowledging Rohan''s exclusion, validating his insecurity, and planning inclusive repair."},"failure_end":{"speaker":"peer","text":"Rohan: whatever. I''m going offline.","reactions":["😢"],"options":[],"isOutcome":true,"outcomeType":"failure","outcomeTitle":"Disconnection","outcomeText":"Disconnection: Rohan checked out. Making assumptions about his schedule, minimizing his exclusion, or calling him defensive invalidated his insecurity and damaged group trust."}}}},"smScenarios":{"1":{"friendName":"Sameer","avatar":"👤","background":"Sameer failed his math quiz despite studying and is feeling discouraged.","peerMessage":"I''m failing everything. I studied for 4 hours last night and still flunked the math quiz. I just feel stupid.","options":[{"text":"Here''s a study plan that might help. We can use my notes.","category":"fixing","angle":35,"why":"You immediately jumped to solving the problem with a study plan, which bypasses Sameer''s feelings of being ''stupid''.","well":"Proactive and shows you are willing to spend your own time to help him study.","miss":"It doesn''t address his hit to his confidence. He might feel like a failure who needs a chore plan rather than a friend who understands his frustration.","alt":"That sounds really overwhelming. You worked so hard last night, it must be so frustrating to see that result."},{"text":"You should really talk to the math teacher and see if you can get extra credit.","category":"advising","angle":90,"why":"You gave advice on next steps (''talk to teacher'') without validating how discouraging it is to fail.","well":"Offers logical, actionable next steps to help him improve his grade.","miss":"It jumps past his immediate pain. When someone is in self-doubt, advice can feel like a lecture on what they did wrong.","alt":"Ugh, that really sucks. You worked so hard too. Let''s take a look at it together later, but for now, take it easy."},{"text":"That sounds really overwhelming. You worked so hard last night, it must be so frustrating to see that result.","category":"supporting","angle":145,"why":"You validated his hard work, mirrored his emotional state, and opened space for him to share without offering a quick fix.","well":"Validates his effort, makes him feel heard, and removes the shame of failing.","miss":"It doesn''t directly fix the grade itself, but it builds the emotional trust needed before problem-solving.","alt":null}]},"2":{"friendName":"Meera","avatar":"👧","background":"Meera sends a voice note sharing her high levels of constant stress and anxiety.","peerMessage":"🔊 Voice Note (0:22): ''I don''t know why I''m so stressed all the time. My skin is breaking out, I''m not sleeping, and my heart feels like it''s racing. I feel like I''m constantly on edge.''","options":[{"text":"Have you tried downloading that meditation app, Calm? It really helped me with my anxiety.","category":"advising","angle":90,"why":"Recommending an app is helpful, but doing it immediately is advice that might feel like homework rather than support.","well":"Shares a practical personal tool that has worked in the past.","miss":"Focuses on quick anxiety relief tips rather than sitting with her and asking what''s creating the stress.","alt":"That sounds exhausting. What do you think is causing all this stress lately?"},{"text":"Let''s go for a walk right now. Exercise decreases cortisol. I''m coming to pick you up.","category":"fixing","angle":35,"why":"You took control of her schedule and actioned a solution immediately, bypassing her agency.","well":"Strong, proactive action that shows deep care and effort to help her feel better.","miss":"Can feel bossy or overwhelming when someone is already stressed out and has low energy.","alt":"Would it help to get out of the house for a bit? We could go for a walk, or just sit somewhere quiet."},{"text":"I can hear how exhausting that is in your voice. Constantly feeling on edge is so draining. I''m here for you.","category":"supporting","angle":145,"why":"You noticed the distress in her voice, validated the physical toll of stress, and offered presence.","well":"Connects emotionally, validates the exhaustion, and avoids pressure to change her mood.","miss":"It does not provide immediate physical solutions, but it helps lower her defenses.","alt":null}]},"3":{"friendName":"Kabir","avatar":"👦","background":"Kabir posts a self-deprecating Close Friends story feeling ignored in the group chat.","peerMessage":"📲 Close Friends Story: ''I feel like nobody would notice if I disappeared from the group chat. I talk and everyone just scrolls past my texts.''","options":[{"text":"I''m sorry you feel that way! We definitely notice you. I''ll make sure to reply to your text next time.","category":"advising","angle":90,"why":"Offering a promise of future action to ''fix'' it is a mix of reassurance and advising, which can feel like pity.","well":"Reassures him that he is seen, and promises better inclusion in the future.","miss":"Reassuring him too quickly might make him feel like he was being dramatic or that you are replying out of obligation.","alt":"Hey, I saw your story. That sucks to feel invisible. I''m really sorry if we''ve been making you feel that way."},{"text":"I''ll text in the group chat right now and tell them we need to be more responsive to each other.","category":"fixing","angle":35,"why":"Taking control and organizing a group talk is a massive fix that might embarrass Kabir and violate his confidence.","well":"Proactive advocacy and standing up for your friend''s inclusion.","miss":"Risks blowing the issue up and creating group drama, making him regret sharing in the first place.","alt":"That''s a really lonely feeling, Kabir. Did something specific happen in the chat today that felt off?"},{"text":"That sounds like a really lonely feeling, Kabir. I know the group chat can get chaotic, but feeling ignored by your friends is awful. I''m sorry.","category":"supporting","angle":145,"why":"You named the emotion (''lonely''), validated the hurt of being ignored by friends, and apologized without making excuses.","well":"Takes relational responsibility, validates the hurt directly, and avoids making excuses about chat busy-ness.","miss":"It doesn''t change the group chat behavior immediately, but it repairs the direct relationship.","alt":null}]},"4":{"friendName":"Zara","avatar":"👧","background":"Zara is stressed by her parents comparing her to her cousin who got into IIT.","peerMessage":"Zara: My parents keep comparing me to my cousin who got into IIT. They literally won''t talk about anything else at dinner. I feel like I''m invisible in my own house.","options":[{"text":"You should tell them how much that hurts you. Communication is key.","category":"advising","angle":90,"why":"Telling someone to confront their parents is highly direct advice, which ignores the power dynamic in an Indian household.","well":"Encourages Zara to practice healthy communication and speak her truth.","miss":"Overlooks how scary and difficult confronting parents can be. It shifts the burden of solving the family dynamic to Zara.","alt":"That must feel incredibly isolating. To feel compared and overlooked in your own home is a really heavy burden. I''m here."},{"text":"Just ignore them. They are just old school. Focus on your own goals.","category":"fixing","angle":35,"why":"Trying to ''solve'' her pain by telling her to ''ignore'' it is a minimization attempt that shuts down her venting.","well":"Attempts to build resilience and keep Zara focused on her long-term goals.","miss":"Dismisses the everyday pain of eating dinner in silence. She can''t easily ''ignore'' her own parents.","alt":"That must feel incredibly isolating. To feel compared and overlooked in your own home is a really heavy burden. I''m here."},{"text":"That must feel incredibly isolating. To feel compared and overlooked in your own home is a really heavy burden. I''m here.","category":"supporting","angle":145,"why":"You validated her sense of isolation and acknowledged the weight of parental comparison without giving simple instructions.","well":"Validates isolation, acknowledges the cultural/familial weight, and offers presence without unsolicited advice.","miss":"It doesn''t solve the parental pressure, but it reminds Zara that she is valued on her own terms.","alt":null}]}},"sm":{"sectionTitle":"The Support Meter","sectionDesc":"Are you supporting, advising, or fixing? Learn the difference between helpful responses and those that miss the mark."}}')
